"""
Config merger. Merges multiple config dicts with precedence rules.
"""
from dataclasses import dataclass, field
from typing import List


class MergeConflict(Exception):
    pass


@dataclass
class MergeReport:
    keys_added: List[str] = field(default_factory=list)
    keys_overridden: List[str] = field(default_factory=list)
    keys_removed: List[str] = field(default_factory=list)
    type_conflicts: List[str] = field(default_factory=list)


def deep_merge(base, override, path="", strategy="override"):
    """Merge override into base, returning a new dict.

    Rules:
    - Scalars: override wins
    - Dicts: recursive merge
    - Lists: concatenate (base + override)
    - None in override: removes the key from base

    strategy:
    - "override" (default): override always wins on type conflicts
    - "strict": raise MergeConflict on type mismatches (list vs scalar, dict vs scalar)
    - "append": when override is scalar and base is list, append scalar to list
    - "protect": base wins on conflicts (override ignored for conflicting keys)
    """
    result = dict(base)

    for key, value in override.items():
        if value is None:
            # None means "remove this key"
            result.pop(key, None)
            continue

        if key in result:
            base_val = result[key]
            key_path = f"{path}.{key}" if path else key

            if isinstance(base_val, dict) and isinstance(value, dict):
                # Both are dicts: recursive merge
                result[key] = deep_merge(base_val, value, key_path, strategy)

            elif isinstance(base_val, list) and isinstance(value, list):
                # Both are lists: concatenate (protect keeps base)
                if strategy == "protect":
                    pass  # base wins
                else:
                    result[key] = base_val + value

            elif isinstance(base_val, list) and not isinstance(value, list):
                # Type conflict: base is list, override is scalar
                if strategy == "strict":
                    raise MergeConflict(
                        f"Type conflict at '{key_path}': "
                        f"base is list, override is {type(value).__name__}"
                    )
                elif strategy == "append":
                    result[key] = base_val + [value]
                elif strategy == "protect":
                    pass  # base wins
                else:  # override
                    result[key] = value

            elif isinstance(base_val, dict) and not isinstance(value, dict):
                # Type conflict: base is dict, override is scalar
                if strategy == "strict":
                    raise MergeConflict(
                        f"Type conflict at '{key_path}': "
                        f"base is dict, override is {type(value).__name__}"
                    )
                elif strategy == "protect":
                    pass  # base wins
                else:  # override or append
                    result[key] = value

            else:
                # Scalar override
                if strategy == "protect":
                    pass  # base wins
                else:
                    result[key] = value
        else:
            result[key] = value

    return result


def merge_configs(*configs, strategy="override"):
    """Merge multiple configs with left-to-right precedence.

    First config is lowest priority, last is highest.

    Example:
        merge_configs(defaults, user_config, cli_overrides)
    """
    if not configs:
        return {}

    result = configs[0]
    for config in configs[1:]:
        result = deep_merge(result, config, strategy=strategy)

    return result


def merge_report(base, override, _path="") -> MergeReport:
    """Analyze what a merge WOULD do without modifying anything.

    Returns a MergeReport describing:
    - keys_added: keys in override not in base
    - keys_overridden: keys changed from base
    - keys_removed: keys set to None in override
    - type_conflicts: keys where types don't match
    """
    report = MergeReport()

    for key, value in override.items():
        full_key = f"{_path}.{key}" if _path else key

        if value is None:
            if key in base:
                report.keys_removed.append(full_key)
        elif key not in base:
            report.keys_added.append(full_key)
        else:
            base_val = base[key]

            if isinstance(base_val, dict) and isinstance(value, dict):
                # Recurse into nested dicts
                sub = merge_report(base_val, value, full_key)
                report.keys_added.extend(sub.keys_added)
                report.keys_overridden.extend(sub.keys_overridden)
                report.keys_removed.extend(sub.keys_removed)
                report.type_conflicts.extend(sub.type_conflicts)
            elif type(base_val) != type(value):
                report.type_conflicts.append(full_key)
                report.keys_overridden.append(full_key)
            else:
                # Same type — value will change
                if base_val != value:
                    report.keys_overridden.append(full_key)

    return report


def flatten_config(config, prefix="", sep="."):
    """Flatten a nested config dict into dot-separated keys.

    Example:
        {"a": {"b": 1, "c": 2}} -> {"a.b": 1, "a.c": 2}
    """
    result = {}
    for key, value in config.items():
        full_key = f"{prefix}{sep}{key}" if prefix else key
        if isinstance(value, dict):
            result.update(flatten_config(value, full_key, sep))
        else:
            result[full_key] = value
    return result


def unflatten_config(flat_config, sep="."):
    """Unflatten dot-separated keys back into nested dict.

    Example:
        {"a.b": 1, "a.c": 2} -> {"a": {"b": 1, "c": 2}}

    Raises TypeError if a key is used both as a scalar and as a section prefix.
    """
    result = {}
    for key, value in flat_config.items():
        parts = key.split(sep)
        target = result
        for part in parts[:-1]:
            if part not in target:
                target[part] = {}
            elif not isinstance(target[part], dict):
                raise TypeError(
                    f"Key conflict in unflatten: '{part}' is already a scalar value "
                    f"but is also used as a section prefix in key '{key}'"
                )
            target = target[part]
        target[parts[-1]] = value
    return result

"""Tests for merge strategies, merge_report, and unflatten_config fix."""
import pytest
from src.merger import deep_merge, merge_configs, merge_report, unflatten_config, MergeConflict, MergeReport


# --- strategy="override" (default behavior) ---

class TestStrategyOverride:
    def test_scalar_override(self):
        assert deep_merge({"a": 1}, {"a": 2}, strategy="override") == {"a": 2}

    def test_list_scalar_replaces(self):
        base = {"tags": ["a", "b"]}
        override = {"tags": "c"}
        result = deep_merge(base, override, strategy="override")
        assert result == {"tags": "c"}

    def test_dict_scalar_replaces(self):
        base = {"db": {"host": "localhost"}}
        override = {"db": "remote"}
        result = deep_merge(base, override, strategy="override")
        assert result == {"db": "remote"}

    def test_list_list_concatenates(self):
        assert deep_merge({"x": [1, 2]}, {"x": [3]}, strategy="override") == {"x": [1, 2, 3]}

    def test_dict_dict_recurses(self):
        base = {"db": {"host": "localhost", "port": 5432}}
        override = {"db": {"port": 3306}}
        assert deep_merge(base, override, strategy="override") == {"db": {"host": "localhost", "port": 3306}}

    def test_none_removes_key(self):
        assert deep_merge({"a": 1, "b": 2}, {"a": None}, strategy="override") == {"b": 2}

    def test_new_key_added(self):
        assert deep_merge({"a": 1}, {"b": 2}, strategy="override") == {"a": 1, "b": 2}


# --- strategy="strict" ---

class TestStrategyStrict:
    def test_scalar_override_ok(self):
        assert deep_merge({"a": 1}, {"a": 2}, strategy="strict") == {"a": 2}

    def test_list_list_ok(self):
        assert deep_merge({"x": [1]}, {"x": [2]}, strategy="strict") == {"x": [1, 2]}

    def test_dict_dict_ok(self):
        base = {"db": {"port": 5432}}
        override = {"db": {"port": 3306}}
        assert deep_merge(base, override, strategy="strict") == {"db": {"port": 3306}}

    def test_list_scalar_raises(self):
        with pytest.raises(MergeConflict, match="list"):
            deep_merge({"tags": ["a"]}, {"tags": "b"}, strategy="strict")

    def test_dict_scalar_raises(self):
        with pytest.raises(MergeConflict, match="dict"):
            deep_merge({"db": {"host": "x"}}, {"db": "remote"}, strategy="strict")

    def test_conflict_message_includes_key(self):
        with pytest.raises(MergeConflict, match="tags"):
            deep_merge({"tags": ["a"]}, {"tags": "b"}, strategy="strict")

    def test_nested_conflict_raises(self):
        base = {"outer": {"inner": [1, 2]}}
        override = {"outer": {"inner": "x"}}
        with pytest.raises(MergeConflict):
            deep_merge(base, override, strategy="strict")

    def test_none_removes_key(self):
        # None removal is not a type conflict
        assert deep_merge({"a": 1, "b": 2}, {"a": None}, strategy="strict") == {"b": 2}


# --- strategy="append" ---

class TestStrategyAppend:
    def test_list_scalar_appends(self):
        base = {"tags": ["a", "b"]}
        override = {"tags": "c"}
        result = deep_merge(base, override, strategy="append")
        assert result == {"tags": ["a", "b", "c"]}

    def test_list_list_concatenates(self):
        assert deep_merge({"x": [1, 2]}, {"x": [3]}, strategy="append") == {"x": [1, 2, 3]}

    def test_scalar_override(self):
        assert deep_merge({"a": 1}, {"a": 2}, strategy="append") == {"a": 2}

    def test_dict_dict_recurses(self):
        base = {"db": {"host": "localhost", "port": 5432}}
        override = {"db": {"port": 3306}}
        assert deep_merge(base, override, strategy="append") == {"db": {"host": "localhost", "port": 3306}}

    def test_dict_scalar_replaces(self):
        # append only special-cases list+scalar; dict+scalar still replaces
        base = {"db": {"host": "x"}}
        override = {"db": "remote"}
        result = deep_merge(base, override, strategy="append")
        assert result == {"db": "remote"}

    def test_append_int_to_list(self):
        base = {"ids": [1, 2]}
        override = {"ids": 3}
        result = deep_merge(base, override, strategy="append")
        assert result == {"ids": [1, 2, 3]}


# --- strategy="protect" ---

class TestStrategyProtect:
    def test_scalar_conflict_base_wins(self):
        assert deep_merge({"a": 1}, {"a": 2}, strategy="protect") == {"a": 1}

    def test_list_scalar_conflict_base_wins(self):
        base = {"tags": ["a", "b"]}
        override = {"tags": "c"}
        result = deep_merge(base, override, strategy="protect")
        assert result == {"tags": ["a", "b"]}

    def test_dict_scalar_conflict_base_wins(self):
        base = {"db": {"host": "localhost"}}
        override = {"db": "remote"}
        result = deep_merge(base, override, strategy="protect")
        assert result == {"db": {"host": "localhost"}}

    def test_list_list_base_wins(self):
        result = deep_merge({"x": [1, 2]}, {"x": [3]}, strategy="protect")
        assert result == {"x": [1, 2]}

    def test_new_key_added(self):
        # Keys only in override are still added
        result = deep_merge({"a": 1}, {"b": 2}, strategy="protect")
        assert result == {"a": 1, "b": 2}

    def test_none_removes_key(self):
        assert deep_merge({"a": 1, "b": 2}, {"a": None}, strategy="protect") == {"b": 2}

    def test_dict_dict_still_recurses(self):
        # Dicts recurse; sub-keys in override not in base are added
        base = {"db": {"host": "localhost", "port": 5432}}
        override = {"db": {"port": 9999, "name": "mydb"}}
        result = deep_merge(base, override, strategy="protect")
        # port is protected (base wins), name is new (added)
        assert result == {"db": {"host": "localhost", "port": 5432, "name": "mydb"}}


# --- merge_report ---

class TestMergeReport:
    def test_keys_added(self):
        report = merge_report({"a": 1}, {"b": 2})
        assert report.keys_added == ["b"]
        assert report.keys_overridden == []

    def test_keys_overridden(self):
        report = merge_report({"a": 1}, {"a": 2})
        assert report.keys_overridden == ["a"]
        assert report.keys_added == []

    def test_keys_removed(self):
        report = merge_report({"a": 1, "b": 2}, {"a": None})
        assert report.keys_removed == ["a"]

    def test_type_conflicts(self):
        report = merge_report({"tags": ["a"]}, {"tags": "b"})
        assert "tags" in report.type_conflicts
        assert "tags" in report.keys_overridden

    def test_dict_type_conflict(self):
        report = merge_report({"db": {"host": "x"}}, {"db": "remote"})
        assert "db" in report.type_conflicts

    def test_nested_keys(self):
        base = {"db": {"host": "localhost", "port": 5432}}
        override = {"db": {"port": 3306, "name": "mydb"}}
        report = merge_report(base, override)
        assert "db.port" in report.keys_overridden
        assert "db.name" in report.keys_added

    def test_no_modification(self):
        base = {"a": 1, "b": [1, 2]}
        override = {"b": "x"}
        original_base = {"a": 1, "b": [1, 2]}
        merge_report(base, override)
        assert base == original_base

    def test_returns_merge_report_instance(self):
        assert isinstance(merge_report({}, {}), MergeReport)

    def test_unchanged_value_not_in_overridden(self):
        # Same value in both — not considered an override
        report = merge_report({"a": 1}, {"a": 1})
        assert "a" not in report.keys_overridden

    def test_none_key_not_in_base_ignored(self):
        # None for key not in base — nothing removed
        report = merge_report({"a": 1}, {"b": None})
        assert report.keys_removed == []
        assert report.keys_added == []

    def test_mixed(self):
        base = {"host": "localhost", "port": 5432, "tags": ["a"], "debug": True}
        override = {"port": 9999, "name": "mydb", "debug": None, "tags": "b"}
        report = merge_report(base, override)
        assert "name" in report.keys_added
        assert "port" in report.keys_overridden
        assert "debug" in report.keys_removed
        assert "tags" in report.type_conflicts


# --- unflatten_config fix ---

class TestUnflattenConflict:
    def test_conflict_raises_type_error(self):
        flat = {"a": 1, "a.b": 2}
        with pytest.raises(TypeError, match="conflict"):
            unflatten_config(flat)

    def test_conflict_message_is_descriptive(self):
        flat = {"a": 1, "a.b": 2}
        with pytest.raises(TypeError) as exc_info:
            unflatten_config(flat)
        assert "a" in str(exc_info.value)

    def test_no_conflict_works(self):
        flat = {"a.b": 1, "a.c": 2}
        assert unflatten_config(flat) == {"a": {"b": 1, "c": 2}}

    def test_deep_conflict_raises(self):
        flat = {"a.b": 1, "a.b.c": 2}
        with pytest.raises(TypeError):
            unflatten_config(flat)
